def agentic_rag(query: str):
    plan_prompt = f"""
    Plan retrieval strategy for: {query}
    Break into 2-3 specific subqueries
    Return as JSON list
    """
    plan = agent.run(plan_prompt)

    all_chunks = []
    for subquery in parse_plan(plan):
        chunks = retrieve_chunks(subquery)
        all_chunks.extend(chunks)

    synthesis_prompt = f"""
    Synthesize answer using ONLY these chunks:
    {all_chunks}
    User query: {query}
    Cite sources with [1], [2] etc.
    """
    return agent.run(synthesis_prompt)

@tool
def synthesize_with_citations(chunks: list, query: str) -> str:
    '''Generate response with source attribution'''
    numbered_chunks = [f'[{i+1}] {chunk}' for i, chunk in enumerate(chunks)]
    prompt = f"""
    Answer using ONLY marked sources:
    {'\n'.join(numbered_chunks)}
    Query: {query}
    Use [1], [2] etc. for citations
    """
    response = llm.invoke(prompt)
    return response

def full_agentic_rag(query: str, max_iters=3):
    context = []
    for i in range(max_iters):
        plan = agent.run(f'Plan next retrieval: {query}')
        new_chunks = retrieve_chunks(plan)
        if confidence_score(new_chunks, context) > 0.8:
            break
        context.extend(new_chunks)

    final_prompt = f'Synthesize final answer: {query}\nContext: {context}'
    return agent.run(final_prompt)

